import json
with open(r"D:\桌面\毕设\exam-platform\data\all_comp_q.json", "r", encoding="utf-8") as f:
    qs = json.load(f)

# 2017
qs.append({"y":2017,"c":"请设计一个算法，将给定的表达式树(二叉树)转换为等价的中缀表达式(通过括号反映操作符的计算次序)并输出。二叉树结点定义如下：typedef struct node{char data[10];struct node*left,*right;}BTree;要求：（1）给出算法的基本设计思想。（2）根据设计思想采用C或C++语言描述算法。","a":"（1）设计思想：中序遍历表达式树。若当前结点为运算符：若为叶子结点直接输出操作数；若为运算符给左子树加括号(若左子树运算符优先级低于当前运算符)递归输出；输出当前运算符；给右子树加括号(若优先级低于等于当前)递归输出。根结点不加外层括号。（2）void toInfix(BTree*root,int depth){if(!root)return;if(!root->left&&!root->right){printf(data);return;}if(depth>0)printf(left_paren);toInfix(root->left,depth+1);printf(data);toInfix(root->right,depth+1);if(depth>0)printf(right_paren);}时间复杂度O(n)。","ch":103,"s":10})
qs.append({"y":2017,"c":"使用Prim(普里姆)算法求带权连通图的最小生成树(MST)。请回答下列问题：（1）对图G从顶点A开始求G的MST，依次给出按算法选出的边。（2）图G的MST是唯一的吗？（3）对任意的带权连通图，满足什么条件时，其MST是唯一的？","a":"（1）Prim算法从A开始：选(A,B)权最小加入B；从{A,B}选(A,D)权次小加入D；从{A,B,D}选(D,C)加入C；从{A,B,D,C}选(C,E)加入E。边序列：(A,B)到(A,D)到(D,C)到(C,E)。（2）若存在权值相等的边可选不同边，则MST可能不唯一。（3）当所有边的权值互不相同时MST唯一。充分必要条件：对图中任意环，环中最大权值的边是唯一的。","ch":104,"s":10})
qs.append({"y":2017,"c":"某计算机系统的内存储器由Cache和主存构成，Cache的存储周期为45ns，主存的存储周期为200ns。已知在一段给定的时间内，CPU共访问内存4500次，其中340次访问主存。（1）Cache的命中率是多少？（2）CPU访问内存的平均时间是多少ns？（3）Cache-主存系统的效率是多少？","a":"（1）命中率=(4500-340)/4500=4160/4500约等于92.44%。（2）平均访问时间=92.44%*45ns+7.56%*200ns约等于41.6ns+15.11ns约等于56.71ns。（3）系统效率=Cache周期/平均访问时间=45/56.71约等于79.3%。","ch":203,"s":20})
qs.append({"y":2017,"c":"某系统中有5个进程P0~P4和3类资源A、B、C，资源总数为(10,5,7)。某时刻分配：P0已分配(0,1,0)最大(7,5,3)；P1(2,0,0)最大(3,2,2)；P2(3,0,2)最大(9,0,2)；P3(2,1,1)最大(2,2,2)；P4(0,0,2)最大(4,3,3)。（1）计算并补全Available。（2）该系统是否处于安全状态？若是给出安全序列。（3）若进程P1请求资源(1,0,2)，用银行家算法判断能否分配。","a":"（1）sum(Allocation)=(7,2,5)，Available=Total-Allocated=(10-7,5-2,7-5)=(3,3,2)。（2）Need=Max-Allocation：P0(7,4,3);P1(1,2,2);P2(6,0,0);P3(0,1,1);P4(4,3,1)。Available(3,3,2)到P1(1,2,2)ok到(5,3,2)到P3(0,1,1)ok到(7,4,3)到P0(7,4,3)ok到(7,5,3)到P2(6,0,0)ok到(10,5,5)到P4(4,3,1)ok。安全序列：P1到P3到P0到P2到P4，安全。（3）P1请求(1,0,2)<=Need(1,2,2)且<=Available(3,3,2)。试分配得Available(2,3,0)，仍可找到安全序列。可以分配。","ch":302,"s":30})
qs.append({"y":2017,"c":"某文件系统采用多级索引分配方式。若每个盘块的大小为4KB，每个盘块号占4B。文件的索引结点中设有10个直接索引项、1个一级间接索引项、1个二级间接索引项和1个三级间接索引项。请回答：（1）普通文件最大可为多少字节？（2）若要访问一个文件中偏移量为1,000,000B处的数据，需要访问几次磁盘？（3）若要访问一个文件中偏移量为100,000,000B处的数据，需要访问几次磁盘？","a":"（1）直接：10*4KB=40KB。一级：4KB/4B=1024个盘块到1024*4KB=4MB。二级：1024^2*4KB=4GB。三级：1024^3*4KB=4TB。总计约4TB。（2）偏移1,000,000B：直接索引10*4KB=40KB<1MB。一级索引：盘块号在inode中一级间接项，读一级间接块(1次)得数据块号读数据块(1次)，共2次。（3）偏移100,000,000B约95.37MB，在二级间接范围(4GB)内。需读二级间接块(1次)到一级间接块(1次)到数据块(1次)，共3次。","ch":304,"s":30})
qs.append({"y":2017,"c":"甲乙双方均采用后退N帧协议(GBN)进行持续的双向数据传输，且双方始终采用捎带确认，帧长均为1000B，发送窗口尺寸均为7。Sx,y和Rx,y分别表示甲方和乙方发送的数据帧，其中x是发送序号，y是确认序号。请说明GBN协议确认序号的含义，并回答：若甲方在发送了S4,2后又连续发送了S5,2和S6,2，但未收到任何确认帧，那么甲方最多还可以发送多少个数据帧？","a":"（1）GBN协议确认序号y表示期望收到序号为y的帧，即y-1及之前的帧均已被正确接收(累积确认)。（2）发送窗口=7，已发送S4,S5,S6(窗口内3个帧)，还可发送7-3=4个数据帧(S7,S0,S1,S2)。后退N帧协议中发送窗口大小=7，已发送未确认帧数=3，剩余可发送=4。","ch":403,"s":40})
qs.append({"y":2017,"c":"假定计算机M字长为16位，按字节编址，采用页式虚拟存储管理。每个进程的虚拟地址空间大小为64KB，页面大小为2KB。（1）虚拟地址中哪些位表示页内偏移？哪些位表示虚页号？（2）TLB采用全相联映射方式，共有8个页表项，每项由虚页号和页框号组成。为使TLB正常工作，虚页号字段和页框号字段各需多少位？（3）访问逻辑地址00081030H，翻译该逻辑地址为物理地址。","a":"（1）64KB=2^16B，虚拟地址16位。页面2KB=2^11B，页内偏移11位。虚页号=16-11=5位。（2）TLB：虚页号5位，页框号计算取决于物理地址空间大小。若物理地址同16位，页框号=16-11=5位。（3）00081030H：虚页号=高5位=1。查页表得页框号，物理地址=页框号<<11|页内偏移。","ch":303,"s":30})

# 2018
qs.append({"y":2018,"c":"给定一个n*n的矩阵，其元素为整数。请设计一个算法，时间上尽可能高效，判断该矩阵是否为对称矩阵(即A[i][j]=A[j][i])。（1）描述算法的基本设计思想。（2）写出该算法的时间和空间复杂度。（3）若矩阵以三元组(行,列,值)的形式按行序主序存储，如何判断对称性？","a":"（1）逐一比较A[i][j]与A[j][i](i<j)，若有不等则非对称。只需比较上三角区域(不含对角线)，减少一半比较量。（2）时间复杂度O(n^2)，空间复杂度O(1)。（3）三元组存储时，对于每个三元组(r,c,v)检查A[c][r]是否存在且等于v；若找不到对应的或值不等则不对称。","ch":101,"s":10})
qs.append({"y":2018,"c":"某计算机采用页式存储管理，页面大小为4KB。主存容量为64MB，按字节编址。（1）物理地址需多少位？（2）若采用一级页表，每个进程的页表最多有多少个页表项？（3）若某进程的虚拟地址空间为2GB，页表项大小为4B，则其页表占多少空间？若页面大小改为8KB，页表占多少空间？","a":"（1）主存64MB=2^26B，物理地址26位。（2）页大小4KB=2^12B，页框数=64MB/4KB=2^14=16384。一级页表最多16384个页表项。（3）虚拟地址2GB=2^31B，页大小4KB到2^31/2^12=2^19=524288个页表项。页表=524288*4B=2MB。页大小8KB到2^31/2^13=2^18=262144项，页表=262144*4B=1MB。","ch":303,"s":30})
qs.append({"y":2018,"c":"某计算机采用5段流水线方式：取指(IF)、译码(ID)、执行(EX)、访存(M)、写回(WB)，各段均为1个时钟周期。指令序列：I1:ADD R1,R2,R3;I2:LOAD R4,0(R1);I3:SUB R5,R4,R2;I4:STORE R5,0(R6)。（1）指出上述指令序列中的数据相关。（2）若采用转发技术，画出流水线时空图。（3）执行该序列共需多少时钟周期？","a":"（1）数据相关：I1到I2(R1写后读RAW)，I2到I3(R4写后读RAW)，I3到I4(R5写后读RAW)。（2）转发技术下：I1的EX段结束即可转发结果给I2的EX段入口，无需等待WB。（3）理想流水线周期=5+(4-1)=8周期。考虑数据相关和转发：I2需等I1 EX完成(1周期停顿)，I3等I2 MEM完成，I4等I3 EX完成。实际约需10-11周期。","ch":205,"s":20})
qs.append({"y":2018,"c":"某文件系统采用索引结点方式，索引结点包含12个直接索引、1个一级间接索引、1个二级间接索引和1个三级间接索引。每个磁盘块大小为1KB，块号占4B。（1）若某文件长度为100KB，则其占用多少磁盘块？（2）访问文件中偏移量为12KB和240KB处的数据，各需访问磁盘多少次(假设索引结点已在内存)？","a":"（1）100KB/1KB=100个磁盘块。（2）偏移12KB：直接索引范围12*1KB=12KB，用第13个直接索引，块号在inode直接索引项中，1次磁盘访问即可。偏移240KB：直接索引12KB不够，一级间接块可存1KB/4B=256个块号到256KB。240KB在一级间接范围内，需读一级间接块(1次)+数据块(1次)=2次。","ch":304,"s":30})
qs.append({"y":2018,"c":"某32位计算机的主存按字节编址，地址空间为4GB。Cache共有16行，每行64B，采用2路组相联映射。（1）主存地址中标记、组号和块内偏移字段各占多少位？（2）若主存地址为0020C0E0H，则它映射到Cache的哪一组？（3）该Cache主要采用SRAM还是DRAM实现？","a":"（1）主存4GB=2^32B。块大小64B=2^6B，块内偏移6位。16行/2路=8组，组号3位。标记=32-6-3=23位。（2）0020C0E0H：块内偏移=后6位=32。组号=接下来的3位=011=3。映射到第3组。（3）Cache采用SRAM实现(速度快、集成度低)。","ch":203,"s":20})
qs.append({"y":2018,"c":"某系统采用时钟(Clock)页面置换算法，页表项中包含访问位和修改位。（1）说明Clock算法的基本原理和置换过程。（2）若系统为进程分配4个页框，页面访问序列为：2,3,2,1,5,2,4,5,3,2,5,2。写出Clock算法下的缺页情况和页框内容变化(假设初始为空，均未修改)。","a":"（1）Clock算法：页框组成环形链表，指针指向最老的页。置换时检查当前指针所指页面：若访问位A=0则选中淘汰；若A=1则置A=0，指针指向下一页重复检查。改进版还检查修改位M。（2）2缺页(2,_,_,_),3缺页(2,3,_,_),2命中,1缺页(2,3,1,_),5缺页(5,3,1,_替换2),2缺页(5,2,1,_替换3),4缺页(5,2,4,_替换1),5命中,3缺页(5,2,4,3),2命中,5命中,2命中。共缺页7次。","ch":303,"s":30})
qs.append({"y":2018,"c":"某网络使用TCP协议进行数据传输，MSS=1KB，RTT=100ms，初始ssthresh=32KB。假设总是不发生拥塞，发送端有足够多的数据要发送，若从慢启动开始，请计算：（1）从开始发送到发送窗口增长到32KB需要多长时间？（2）从32KB增长到64KB需要多长时间？（3）从开始发送到发送完1MB数据需要的最短时间是多少？","a":"（1）慢启动：cwnd指数增长(每RTT加倍)。初始cwnd=1MSS=1KB。增长：1到2到4到8到16到32KB，需5个RTT=500ms。（2）到达ssthresh(32KB)后进入拥塞避免：每个RTT线性+1MSS。32到33到...到64KB需32个RTT=3.2s。（3）1MB=1024KB。慢启动期5RTT发送总量=1+2+4+8+16=31KB。还需993KB。后续拥塞避免cwnd从32线性增长。总时间约需20个RTT左右。","ch":405,"s":40})

